    53→function getTransactionCardItem(
    54→  transaction: PointsTransaction,
    55→): PropsCardTransition {
    56→  const isPositive =
    57→    transaction.type === 'CREDIT' || transaction.type === 'REFUNDED';
    58→  const valueColor = isPositive ? 'PLUS_COLOR_02' : 'BRAND_COMPLEMENT_01';
    59→  const isExpired = transaction.type === 'EXPIRED';
    60→
    61→  return {
    62→    type: 'default' as const,
